import { useQuery } from '@tanstack/react-query';
import {
  lazy,
  startTransition,
  Suspense,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from 'react';

import { type HomeView } from '@/features/home/components/molecules/session-view-tabs';
import { MainTopbar } from '@/features/home/components/organisms/main-topbar';
import { ProjectOrchestratorSidebar } from '@/features/home/components/organisms/project-orchestrator-sidebar';
import { SessionWorkspacePanel } from '@/features/home/components/organisms/session-workspace-panel';
import {
  fallbackHomeWorkspace,
  fetchHomeWorkspace,
  homeWorkspaceQueryKey,
} from '@/features/home/data/workspace';
import {
  getKanbanColumns,
  getSelectedWorkerSession,
  getTerminalSession,
  getWorkerSessionGroups,
  getWorkerSessionSelectionKey,
  withSelectedWorkerSession,
} from '@/features/home/domain/session-workspace';
import { OrchestratorWorkspaceTemplate } from '@/features/home/templates/orchestrator-workspace-template';

const DevAcceptanceRig = import.meta.env.DEV
  ? lazy(() =>
      import('@/features/home/dev/acceptance-rig').then((module) => ({
        default: module.DevAcceptanceRig,
      }))
    )
  : undefined;

const workspaceRefreshIntervalMs = 5_000;

export function OrchestratorHomePage() {
  const [view, setView] = useState<HomeView>('kanban');
  const workspaceQuery = useQuery({
    enabled: typeof window !== 'undefined',
    queryFn: fetchHomeWorkspace,
    queryKey: homeWorkspaceQueryKey,
    refetchInterval: workspaceRefreshIntervalMs,
    retry: false,
  });
  const workspace = workspaceQuery.data ?? fallbackHomeWorkspace;
  const [selectedWorkerSessionKey, setSelectedWorkerSessionKey] = useState(
    () => {
      const selectedSession = getSelectedWorkerSession(
        fallbackHomeWorkspace.sessions
      );
      return selectedSession
        ? getWorkerSessionSelectionKey(selectedSession)
        : undefined;
    }
  );
  const [selectedTerminalSessionKey, setSelectedTerminalSessionKey] = useState(
    selectedWorkerSessionKey
  );
  const sessions = useMemo(
    () =>
      withSelectedWorkerSession(workspace.sessions, selectedWorkerSessionKey),
    [selectedWorkerSessionKey, workspace.sessions]
  );
  const selectedWorkerSession = getSelectedWorkerSession(sessions);
  const terminalSessions = useMemo(
    () => [...(workspace.orchestrators ?? []), ...sessions],
    [sessions, workspace.orchestrators]
  );
  const selectedTerminalSession =
    getTerminalSession(terminalSessions, selectedTerminalSessionKey) ??
    selectedWorkerSession ??
    terminalSessions[0];
  const kanbanColumns = useMemo(() => getKanbanColumns(sessions), [sessions]);
  const workerSessionGroups = useMemo(
    () => getWorkerSessionGroups(sessions),
    [sessions]
  );
  const workspaceState = workspaceQuery.isPending
    ? 'loading'
    : workspaceQuery.isError
      ? 'error'
      : sessions.length === 0
        ? 'empty'
        : 'ready';

  useEffect(() => {
    if (!selectedWorkerSession) {
      return;
    }

    const selectedKey = getWorkerSessionSelectionKey(selectedWorkerSession);
    setSelectedWorkerSessionKey((currentSessionKey) =>
      currentSessionKey === selectedKey ? currentSessionKey : selectedKey
    );
  }, [selectedWorkerSession]);

  useEffect(() => {
    if (!selectedTerminalSession) {
      return;
    }

    const selectedKey = getWorkerSessionSelectionKey(selectedTerminalSession);
    setSelectedTerminalSessionKey((currentSessionKey) => {
      if (getTerminalSession(terminalSessions, currentSessionKey)) {
        return currentSessionKey;
      }

      return selectedKey;
    });
  }, [selectedTerminalSession, terminalSessions]);

  const handleViewChange = useCallback((nextView: HomeView) => {
    startTransition(() => {
      setView((currentView) =>
        currentView === nextView ? currentView : nextView
      );
    });
  }, []);

  const handleWorkerSessionOpen = useCallback((selectionKey: string) => {
    startTransition(() => {
      setSelectedWorkerSessionKey(selectionKey);
      setSelectedTerminalSessionKey(selectionKey);
      setView('terminal');
    });
  }, []);

  const handleTerminalSessionOpen = useCallback((selectionKey: string) => {
    startTransition(() => {
      setSelectedTerminalSessionKey(selectionKey);
      setView('terminal');
    });
  }, []);

  const page = (
    <OrchestratorWorkspaceTemplate
      primarySidebar={
        <ProjectOrchestratorSidebar
          onOrchestratorSessionSelect={handleTerminalSessionOpen}
          projects={workspace.projects}
          selectedProjectId={
            selectedTerminalSession?.project ?? workspace.activeProjectId
          }
          selectedTerminalSessionKey={selectedTerminalSessionKey}
          selectedWorkerSessionKey={selectedWorkerSessionKey}
          onWorkerSessionSelect={handleWorkerSessionOpen}
          orchestrators={workspace.orchestrators ?? []}
          workerSessionGroups={workerSessionGroups}
        />
      }
      topbar={<MainTopbar view={view} onViewChange={handleViewChange} />}
      main={
        <SessionWorkspacePanel
          kanbanColumns={kanbanColumns}
          onWorkerSessionSelect={handleWorkerSessionOpen}
          onWorkspaceRefresh={() => {
            void workspaceQuery.refetch();
          }}
          selectedTerminalSession={selectedTerminalSession}
          view={view}
          workspaceError={
            workspaceQuery.error instanceof Error
              ? workspaceQuery.error.message
              : undefined
          }
          workspaceState={workspaceState}
        />
      }
    />
  );

  if (!DevAcceptanceRig) {
    return page;
  }

  return (
    <>
      {page}
      <Suspense fallback={null}>
        <DevAcceptanceRig view={view} onViewChange={handleViewChange} />
      </Suspense>
    </>
  );
}

