function ProjectNavItem(props: {
  onOrchestratorSessionSelect: (selectionKey: string) => void;
  onWorkerSessionSelect: (selectionKey: string) => void;
  orchestrators: WorkerSession[];
  project: ProjectOrchestrator;
  selected: boolean;
  selectedTerminalSessionKey?: string;
  selectedWorkerSessionKey?: string;
  workerSessionGroups: WorkerSessionGroupData[];
}) {
  const [open, setOpen] = useState(props.selected);

  useEffect(() => {
    if (props.selected) {
      setOpen(true);
    }
  }, [props.selected]);

  return (
    <SidebarMenuItem>
      <Collapsible open={open} onOpenChange={setOpen}>
        <CollapsibleTrigger
          render={
            <SidebarMenuButton
              type="button"
              className="h-9 rounded-none text-sm leading-5"
            />
          }
        >
          <ChevronDownIcon
            aria-hidden="true"
            className={open ? undefined : '-rotate-90'}
          />
          {open ? (
            <FolderOpenIcon aria-hidden="true" />
          ) : (
            <FolderIcon aria-hidden="true" />
