import {
  AlertTriangleIcon,
  RefreshCcwIcon,
  SquareTerminalIcon,
} from 'lucide-react';
import { useEffect, useState } from 'react';

import { cn } from '@/lib/tailwind/utils';

import { Button } from '@/components/ui/button';
import { Spinner } from '@/components/ui/spinner';

import type { HomeView } from '@/features/home/components/molecules/session-view-tabs';
import { KanbanBoard } from '@/features/home/components/organisms/kanban-board';
import { TerminalPanel } from '@/features/home/components/organisms/terminal-panel';
import type {
  KanbanColumnData,
  WorkerSession,
} from '@/features/home/domain/session-workspace';

export type WorkspacePanelState = 'empty' | 'error' | 'loading' | 'ready';

export function SessionWorkspacePanel(props: {
  kanbanColumns: KanbanColumnData[];
  onWorkerSessionSelect: (selectionKey: string) => void;
  onWorkspaceRefresh: () => void;
  selectedTerminalSession?: WorkerSession;
  view: HomeView;
  workspaceError?: string;
  workspaceState: WorkspacePanelState;
}) {
  const [hasOpenedTerminal, setHasOpenedTerminal] = useState(
    props.view === 'terminal'
  );
  const isKanbanActive = props.view === 'kanban';
  const shouldRenderTerminal = hasOpenedTerminal || props.view === 'terminal';

  useEffect(() => {
    if (props.view !== 'terminal') {
      return;
    }

    setHasOpenedTerminal(true);
  }, [props.view]);

  return (
    <div className="relative flex min-h-0 min-w-0 flex-1">
      <div
        aria-hidden={isKanbanActive ? undefined : true}
        className={cn(
          'relative flex min-h-0 min-w-0 flex-1',
          !isKanbanActive && 'hidden'
        )}
      >
        <KanbanBoard
          className="flex-1"
          columns={props.kanbanColumns}
          onSessionSelect={props.onWorkerSessionSelect}
        />
        {props.workspaceState !== 'ready' ? (
          <WorkspaceStatusView
            className="absolute inset-0"
            error={props.workspaceError}
            onRefresh={props.onWorkspaceRefresh}
            state={props.workspaceState}
          />
        ) : null}
      </div>

      {shouldRenderTerminal && props.selectedTerminalSession ? (
        <TerminalPanel
          hidden={isKanbanActive}
          session={props.selectedTerminalSession}
        />
      ) : null}

      {shouldRenderTerminal && !props.selectedTerminalSession ? (
        <section
          aria-hidden={isKanbanActive ? true : undefined}
          aria-label="Worker terminal panel"
          data-acceptance-anchor="terminal-panel"
          hidden={isKanbanActive}
          className="flex min-h-90 min-w-0 flex-1 flex-col border-b border-border bg-background md:min-h-0 md:border-b-0"
        >
          <WorkspaceStatusView
            error={props.workspaceError}
            onRefresh={props.onWorkspaceRefresh}
            state={
              props.workspaceState === 'ready' ? 'empty' : props.workspaceState
            }
            tone="terminal"
          />
        </section>
      ) : null}
    </div>
  );
}

function WorkspaceStatusView(props: {
  className?: string;
  error?: string;
  onRefresh: () => void;
  state: Exclude<WorkspacePanelState, 'ready'>;
  tone?: 'default' | 'terminal';
}) {
  const content = getWorkspaceStatusContent(props.state, props.error);
  const isLoading = props.state === 'loading';

  return (
    <div
      className={cn(
        'flex min-h-0 min-w-0 flex-1 items-center justify-center bg-background/95 p-6 text-center',
        props.className
      )}
    >
      <div className="flex max-w-sm flex-col items-center gap-3">
        <span
          className={cn(
            'flex size-9 items-center justify-center border border-border bg-background text-muted-foreground',
            props.tone === 'terminal' && 'bg-muted/30'
          )}
        >
          {isLoading ? (
            <Spinner className="size-4" />
          ) : props.state === 'error' ? (
            <AlertTriangleIcon className="size-4" />
          ) : (
            <SquareTerminalIcon className="size-4" />
          )}
        </span>
        <div className="space-y-1">
          <h2 className="text-sm leading-5 font-medium text-foreground">
            {content.title}
          </h2>
          <p className="text-xs leading-5 text-muted-foreground">
            {content.description}
          </p>
